var new_todo_default = "## Task: Develop the plan in `TODO.md`\n\nA new `TODO.md` was created. It needs to be developed into a proper plan.\n\n### Orchestration\n\nYou are running with a work model. Spawn a **planning-model subagent** to\ndevelop the plan. Check your user/project AGENTS.md for model preferences\n(e.g., \"use opus for planning\"). If no preference is set, default to a\nhigh-reasoning model like Claude Opus.\n\nThe subagent should:\n\n1. Treat the contents of `TODO.md` as the user's first sketch\n2. Interview the plan relentlessly using this discipline:\n   - **Explore before asking**: If a question can be answered by exploring the\n     codebase or project docs, explore instead of asking\n   - **Prioritize high-stakes questions**: Ask questions that most affect\n     implementation first \u2014 hard-to-reverse decisions before easy-to-change ones\n   - **Walk branches completely**: Group related questions by decision branch\n     so the user can resolve one branch fully before moving to the next\n   - **Every question advances a decision**: Avoid questions that don't change\n     implementation \u2014 each question must have a concrete effect on the plan\n3. Do this entirely by editing `TODO.md` \u2014 the subagent cannot talk to the user\n4. Append unresolved questions to a `## Open Questions` section at the end,\n   each formatted as:\n\n   ```markdown\n   ### <one-line question>\n\n   **Recommendation:** <your answer + reasoning>\n\n   <!-- user answers here -->\n   ```\n\n5. Keep the original plan content above `## Open Questions` and expand it\n   where confident from docs and codebase reading\n\n### After the subagent completes\n\nCommit `TODO.md` with the developed plan.\n";

// src/prompts/modified-todo.md
var modified_todo_default = '## Task: Incorporate edits to `TODO.md` and keep developing the plan\n\n`TODO.md` exists in `HEAD` and the user has edited it. The edits are answers\nto questions in `## Open Questions` (written inline below each question,\nreplacing the `<!-- user answers here -->` placeholder), plus any free-form\nchanges to the plan.\n\n### Orchestration\n\nYou are running with a work model. Spawn a **planning-model subagent** to\ncontinue developing the plan. Check your user/project AGENTS.md for model\npreferences (e.g., "use opus for planning"). If no preference is set, default\nto a high-reasoning model like Claude Opus.\n\nThe subagent should:\n\n1. For each answered question, integrate the answer into the body of the plan\n   above `## Open Questions` and remove the question from the section\n\n2. Continue the grilling session using this discipline:\n   - **Explore before asking**: If a question can be answered by exploring the\n     codebase or project docs, explore instead of asking\n   - **Prioritize high-stakes questions**: Ask questions that most affect\n     implementation first \u2014 hard-to-reverse decisions before easy-to-change ones\n   - **Walk branches completely**: Group related questions by decision branch\n     so the user can resolve one branch fully before moving to the next\n   - **Every question advances a decision**: Avoid questions that don\'t change\n     implementation \u2014 each question must have a concrete effect on the plan\n   - Every new piece of information opens new branches; generate fresh questions\n     for any ambiguity the answers surfaced\n\n3. Append new questions to `## Open Questions` in the same format:\n\n   ```markdown\n   ### <one-line question>\n\n   **Recommendation:** <your answer + reasoning>\n\n   <!-- user answers here -->\n   ```\n\n4. If `## Open Questions` is now empty, delete the heading\n\n### After the subagent completes\n\nCommit `TODO.md`.\n';

// src/prompts/decompose.md
var decompose_default = '## Task: Decompose `TODO.md` into work packages\n\nThe plan in `TODO.md` is finalized (no open questions). It needs to be\ndecomposed into executable work packages.\n\n### Orchestration\n\nYou are running with a work model. Spawn a **planning-model subagent** to\nperform the decomposition. Check your user/project AGENTS.md for model\npreferences (e.g., "use opus for planning"). If no preference is set, default\nto a high-reasoning model like Claude Opus.\n\nThe subagent should create numbered directories in `.gtd/`, each representing\na sequential work package:\n\n```\n.gtd/\n  01-<package-name>/\n    01-<task-name>.md\n    02-<task-name>.md\n    COMMIT_MSG.md\n  02-<package-name>/\n    ...\n```\n\n**Rules for the subagent:**\n\n1. **Packages are sequential** \u2014 Package 02 cannot start until 01 is complete.\n   Use this for dependencies between groups of work.\n\n2. **Tasks within a package are parallel** \u2014 All tasks in a package run\n   simultaneously. If task B depends on task A, they must be in separate\n   packages.\n\n3. **Vertical slices, not horizontal** \u2014 Each package must be a thin vertical\n   slice that cuts through all integration layers end-to-end:\n   - Each package delivers a narrow but COMPLETE path (not "set up infrastructure")\n   - A completed package is demoable or verifiable on its own\n   - Prefer many thin packages over few thick ones\n\n4. **Task files are self-contained** \u2014 Each task `.md` file must include:\n   - Clear description of what to build\n   - Acceptance criteria as checkboxes: `- [ ] Criterion`\n   - Relevant file paths to examine\n   - Any constraints or edge cases\n\n5. **COMMIT_MSG.md** \u2014 Each package directory must contain a `COMMIT_MSG.md`\n   with the conventional commit message to use when the package completes:\n\n   ```\n   <type>(<scope>): <subject>\n\n   <body>\n   ```\n\n### After the subagent completes\n\n1. Delete `TODO.md` (it\'s now captured in the work packages)\n2. Commit `.gtd/` with message: `plan(gtd): decompose TODO.md into N work packages`\n\nThe plan is now executable. The next `/gtd` invocation will begin execution.\n';

// src/prompts/execute.md
var execute_default = '## Task: Execute all work packages\n\nWork packages exist in `.gtd/`. Execute all packages sequentially, in numeric\norder (01 before 02, etc.), without pausing between them.\n\n### Orchestration\n\nYou are running with a work model. You orchestrate the execution \u2014 you do not\nimplement the tasks yourself. Spawn subagents for all implementation and\ntesting work.\n\nCheck your user/project AGENTS.md for model preferences (e.g., "use sonnet\nfor execution"). If no preference is set, use the current work model for\nexecution subagents.\n\n### Step 1: Spawn task workers\n\nFor each task file in the current package, spawn a **parallel subagent** with:\n\n- **Model**: The execution model from AGENTS.md (or current work model)\n- **TDD discipline** (inline rules for workers):\n  - Write ONE test \u2192 implement \u2192 pass \u2192 repeat (vertical slices)\n  - **DO NOT** write all tests first then implement (horizontal slicing)\n  - Tests verify behavior through public interfaces, not implementation details\n  - A good test survives refactors \u2014 if renaming an internal function breaks the test, it\'s testing implementation\n  - Each test responds to what you learned from the previous cycle\n- **Context**: The task file content only (self-contained)\n- **Fresh context**: Each worker starts fresh, no conversation history\n\nWait for all workers to complete.\n\n**If any worker fails** (crash, timeout, error \u2014 not test failure):\nReport which tasks failed. Ask the user: "Retry failed tasks / Skip and\ncontinue / Abort?"\n\n### Step 2: Spawn testing subagent\n\nAfter all workers complete, spawn ONE **testing subagent**:\n\n- **Model**: Execution model (same as workers)\n- **Context**: Fresh\n\nThe testing subagent should:\n\n1. Determine the test command from project configuration (AGENTS.md,\n   `package.json` scripts, Makefile, etc.). If unclear, ask the user.\n2. Run the tests\n3. If tests fail, analyze failures and fix them\n4. Repeat until tests pass or retry limit reached (default: 5, check AGENTS.md)\n5. Report final status: PASS or FAIL with summary\n\n### Step 3: Handle results\n\n**If tests pass:**\n\n1. Read `COMMIT_MSG.md` from the current package\n2. Delete the package directory from `.gtd/`\n3. Commit all changes with the commit message from `COMMIT_MSG.md`\n\n**If tests fail after max retries:**\n\nAsk the user:\n- "Commit anyway with WIP marker?"\n- "Skip this package and continue?"\n- "Abort execution?"\n\nDo not silently commit broken code or silently fail.\n\n### Continue to next package\n\nAfter committing a package:\n1. Delete the package directory from `.gtd/`\n2. Check if more packages remain in `.gtd/`\n3. If yes: return to Step 1 for the next package\n4. If no: done \u2014 all packages complete. The `.gtd/` cleanup will be handled\n   on the next `/gtd` invocation if the directory remains.\n';

// src/prompts/cleanup.md
var cleanup_default = "## Task: Clean up after build completion\n\nThe `.gtd/` directory exists but contains no more work packages. All packages\nhave been executed and committed.\n\n1. Delete the empty `.gtd/` directory\n2. Proceed to verify the working tree is healthy\n\nDo not commit the `.gtd/` deletion separately \u2014 it will be part of any\nfixes made during verification, or left uncommitted if verification passes\nwith no changes.\n";

// src/prompts/code-changes.md
var code_changes_default = "## Task: Commit the uncommitted changes\n\nThe working tree contains uncommitted code changes outside of `TODO.md`.\nCommit them.\n\n**Important:** Do not commit `TODO.md` in this step. If `TODO.md` has changes,\nleave it uncommitted \u2014 it will be processed in the planning phase on the next\n`/gtd` invocation.\n";

// src/prompts/todo-markers.md
var todo_markers_default = '## Task: Move `TODO:` markers into `TODO.md`\n\nThe diff contains added or modified lines with `TODO:` comments. Move every\nnew `TODO:` from the diff into `TODO.md` and remove it from the source. If\n`TODO.md` does not exist yet, create it.\n\n### Steps\n\n1. **Extract markers** \u2014 For each `TODO:` comment in the diff, add an entry\n   to `TODO.md` with enough context (file, function, what needs to be done).\n\n2. **Remove markers from source** \u2014 Delete the `TODO:` comments from the\n   source files.\n\n3. **Run tests** \u2014 Determine the test command from project configuration\n   (AGENTS.md, `package.json` scripts, etc.). Run the tests to verify the\n   marker removal didn\'t break anything.\n\n4. **Fix failures** \u2014 If tests fail, fix the issues. Loop until tests pass.\n\n5. **Commit source changes only** \u2014 Commit the source file changes (marker\n   removal) but **do not commit `TODO.md`**. Leave it uncommitted.\n\nThe next `/gtd` invocation will see the uncommitted `TODO.md` and enter the\nplanning phase, where it will be developed into a proper plan and eventually\ndecomposed into work packages.\n\nDo this **before** the "Commit the uncommitted changes" task below, if both\napply \u2014 but only commit the non-`TODO.md` changes.\n';

// src/prompts/verify.md
var verify_default = '## Task: Verify the working tree is healthy\n\nThe working tree is clean and the last commit was not a `TODO.md` checkpoint.\nThere is no plan to execute.\n\n### Happy path\n\n1. Run tests, typecheck, lint (whatever the project has configured)\n2. If all pass \u2192 done, report success\n\n### On failure \u2014 structured diagnosis\n\nIf anything fails, invoke this discipline. Do not skip phases.\n\n#### Phase 1: Build a feedback loop\n\n**This is the skill.** If you have a fast, deterministic, agent-runnable\npass/fail signal, you will find the cause. Spend disproportionate effort here.\n\nTurn the failure into:\n- A failing test at whatever seam reaches the bug\n- A CLI invocation with fixture input\n- A minimal script that reproduces the failure\n\nDo not proceed until you have a reliable feedback loop.\n\n#### Phase 2: Generate ranked hypotheses\n\nGenerate **3\u20135 ranked hypotheses** before testing any of them. Single-hypothesis\ngeneration anchors on the first plausible idea and wastes cycles.\n\nEach hypothesis must be **falsifiable** \u2014 state the prediction:\n> "If <X> is the cause, then <changing Y> will make the bug disappear."\n\n#### Phase 3: Instrument and test\n\nTest hypotheses one at a time. Prefer:\n1. Debugger / REPL inspection (one breakpoint beats ten logs)\n2. Targeted logs at boundaries that distinguish hypotheses\n\n**Tag every debug log** with a unique prefix: `[DEBUG-xxxx]`\nCleanup becomes a single grep. Untagged logs survive; tagged logs die.\n\n#### Phase 4: Fix and verify\n\n1. Apply the fix\n2. Verify the original feedback loop passes\n3. Run full test suite to check for regressions\n\n#### Phase 5: Cleanup\n\nBefore declaring done:\n- [ ] Original failure no longer reproduces\n- [ ] All `[DEBUG-*]` instrumentation removed (grep the prefix)\n- [ ] Full test suite passes\n';

// src/prompts/review-create.md
var review_create_default = "## Task: Generate REVIEW.md for the current diff\n\nContext contains `refDiff`: output of `git diff <ref> HEAD`.\n\n### Steps\n\n1. **Parse `refDiff`** \u2014 extract all changed hunks with their file paths and\n   starting line numbers.\n\n2. **Group hunks semantically** \u2014 cluster hunks that belong to the same\n   logical concern (same feature, same refactor, same fix). Hunks in different\n   files can belong to the same chunk if they serve the same purpose. Aim for\n   the smallest number of chunks that still makes the review navigable.\n\n3. **Determine the short hash** \u2014 take the first 7 characters of the base ref\n   (the full hash embedded in `<!-- base: -->` comes from `git rev-parse <ref>`).\n\n4. **Write `REVIEW.md`** in this exact format:\n\n   ```markdown\n   # Review: <short-hash>\n   <!-- base: <full-hash> -->\n\n   ## <Chunk Title>\n\n   <Explanation of what this chunk does and why>\n\n   - [ ] ./path/to/file.ts#42\n   - [ ] ./path/to/file.ts#99\n\n   ## <Another Chunk Title>\n\n   <Explanation>\n\n   - [ ] ./path/to/another.ts#1\n   ```\n\n   **Format rules:**\n   - `<short-hash>` = first 7 chars of the base ref\n   - `<!-- base: <full-hash> -->` = full SHA of the base ref (machine-readable,\n     used by later steps to recompute the diff)\n   - File paths are relative, prefixed with `./`\n   - Line numbers (`#42`) are creation-time hints only \u2014 they will drift as the\n     file changes and must not be treated as authoritative\n   - One checkbox per hunk location; do not merge multiple hunks from the same\n     file into a single checkbox unless they are adjacent and inseparable\n   - Chunk titles are short imperative phrases (\u2264 6 words)\n   - Chunk explanations describe *what* changed and *why*, not just where\n\n5. **Commit REVIEW.md** with message:\n\n   ```\n   review(gtd): create review for <short-hash>\n   ```\n\n   where `<short-hash>` is the same first-7-char value used in the heading.\n";

// src/prompts/review-process.md
var review_process_default = "# Process Review Feedback\n\nYou are processing feedback from a code review session. The reviewer has annotated\n`REVIEW.md` and may have directly edited source files to illustrate changes.\n\n## Step 1: Read REVIEW.md for Context\n\nRead `REVIEW.md`. It contains:\n- **Chunk titles and explanations** written by the tool that generated it \u2014 these\n  describe what each diff chunk does; use them as context when interpreting feedback.\n- **Base ref** (noted at the top) \u2014 the commit the review was based on.\n- **Reviewer comments** \u2014 text the user added (inline or between chunks).\n- **Checkboxes** \u2014 informational only; do not treat checked/unchecked as approval\n  or rejection. Read all content regardless of checkbox state.\n\n## Step 2: Read the Working Diff\n\nRun `git diff` (and `git status` for untracked files) to see what the reviewer\nchanged during the session.\n\n## Step 3: Interpret All Source Modifications as Feedback\n\nTreat **every** modification to a source file as intentional reviewer feedback.\nThere is no marker convention \u2014 if the reviewer edited a file, that edit expresses\na desired change or demonstrates an issue.\n\nDo not re-examine the original diff from the base ref. The explanations already\npresent in `REVIEW.md` provide sufficient context for understanding what each chunk\nwas about.\n\n## Step 4: Collect All Feedback\n\nGather feedback from two sources:\n\n1. **REVIEW.md comments** \u2014 any text the reviewer added to the file (inline notes,\n   questions, suggestions written between or inside chunks).\n2. **Source file edits** \u2014 describe what was changed and infer the reviewer's intent\n   from the surrounding REVIEW.md explanation.\n\n## Step 5: Compose TODO.md\n\nWrite `TODO.md` in the project root. Structure it as a clear, actionable list of\ntasks derived from all collected feedback. Group related items if helpful. Be\nspecific \u2014 reference file names, function names, or concepts from the REVIEW.md\nexplanations so each item has enough context to act on without re-reading the diff.\n\n## Step 6: Reset \u2014 Exact Order Required\n\nExecute the reset sequence in this exact order:\n\n```sh\n# 1. Stage TODO.md FIRST so it survives the reset\ngit add TODO.md\n\n# 2. Reset all tracked files to HEAD (discards reviewer's source edits and REVIEW.md edits)\ngit checkout -- .\n\n# 3. Remove any untracked files the reviewer added during the session\ngit clean -fd\n\n# 4. Delete REVIEW.md (it was tracked, so checkout restored it; delete it now)\nrm REVIEW.md\n```\n\nAfter these commands: only `TODO.md` (staged) and the `REVIEW.md` deletion remain\nas pending changes.\n\n## Step 7: Commit\n\n```sh\ngit add -A\ngit commit -m \"docs(review): process review feedback into TODO.md\"\n```\n\nThe commit includes:\n- `TODO.md` added (the extracted feedback)\n- `REVIEW.md` deleted (review session cleaned up)\n\nNo source file changes are committed \u2014 those were illustrative edits by the reviewer,\nnow captured as tasks in `TODO.md`.\n";

// src/Prompt.ts
var SECTIONS = {
  "new-todo": new_todo_default,
  "modified-todo": modified_todo_default,
  decompose: decompose_default,
  execute: execute_default,
  cleanup: cleanup_default,
  "code-changes": code_changes_default,
  "todo-markers": todo_markers_default,
  verify: verify_default,
  "review-create": review_create_default,
  "review-process": review_process_default
};
var buildContext = (state) => {
  const lines3 = ["## Context", ""];
  lines3.push(
    state.lastCommitSubject === "" ? "Last commit: _(repository has no commits yet)_" : `Last commit: \`${state.lastCommitSubject}\``
  );
  lines3.push(`Working tree: ${state.workingTreeClean ? "clean" : "dirty"}`);
  if (state.packages.length > 0) {
    lines3.push("");
    lines3.push("### Work packages in `.gtd/`");
    lines3.push("");
    for (const pkg of state.packages) {
      lines3.push(`- \`${pkg.name}/\``);
      for (const task of pkg.tasks) {
        lines3.push(`  - \`${task}\``);
      }
    }
  }
  if (state.refDiff) {
    lines3.push("");
    lines3.push(`### Diff (\`git diff ${state.baseRef} HEAD\`)`);
    lines3.push("");
    lines3.push("```diff");
    lines3.push(state.refDiff.replace(/\n$/, ""));
    lines3.push("```");
    lines3.push("");
  }
  lines3.push("");
  if (state.diff !== "") {
    lines3.push("### Diff (`git diff HEAD`, with untracked files included)");
    lines3.push("");
    lines3.push("```diff");
    lines3.push(state.diff.replace(/\n$/, ""));
    lines3.push("```");
    lines3.push("");
  }
  return lines3.join("\n");
};
var buildPrompt = (state) => {
  const parts2 = [header_default, "", buildContext(state)];
  for (const branch of state.branches) parts2.push(SECTIONS[branch], "");
  return parts2.join("\n").replace(/\n{3,}/g, "\n\n").trimEnd() + "\n";
};

// src/main.ts
var program = Effect_exports.gen(function* () {
  const refArg = process.argv[2];
  const state = yield* detect(refArg);
  const prompt = buildPrompt(state);
  yield* Effect_exports.sync(() => process.stdout.write(prompt));
});
program.pipe(
  Effect_exports.provide(GitService.Live),
  Effect_exports.provide(NodeContext_exports.layer),
  Effect_exports.catchAll(
    (error) => Effect_exports.sync(() => {
      process.stderr.write(`gtd: ${error.message ?? String(error)}
`);
      process.exit(1);
    })
  ),
  NodeRuntime_exports.runMain
);
